declare module "rwsdk/worker" {
  interface DefaultAppContext {
    requestId: string;
  }
}

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

export type AppContext = {};

// Request logging middleware – runs on every request before route matching.
// Uses console.log to emit a structured JSON line per request; a wrapper
// script tees these lines into /home/user/myproject/logs/access.log.
const requestLogger = async ({
  request,
  response,
  ctx,
}: {
  request: Request;
  response: ResponseInit & { headers: Headers };
  ctx: AppContext & { requestId?: string };
}) => {
  const requestId = crypto.randomUUID();
  ctx.requestId = requestId;
  response.headers.set("X-Request-Id", requestId);

  const startTime = performance.now();

  // Use a microtask to hook into the response just before it's sent.
  // The middleware pattern here doesn't give us direct access to the final
  // response, so we schedule a deferred log that captures the state after
  // all handlers have run.
  const logRequest = () => {
    const durationMs = Math.round((performance.now() - startTime) * 100) / 100;
    const url = new URL(request.url);
    const logEntry = {
      ts: new Date().toISOString(),
      method: request.method.toUpperCase(),
      path: url.pathname,
      status: response.status ?? 200,
      durationMs,
      requestId,
      userAgent: request.headers.get("User-Agent") ?? "",
    };
    console.log(`__RW_ACCESS_LOG__${JSON.stringify(logEntry)}`);
  };

  // Schedule the log to run after the response is built.
  // We use queueMicrotask to run after all synchronous middleware finishes
  // but before the response is actually sent. However, since route handlers
  // may be async, we need to hook later. The approach: wrap the actual
  // response handling by patching the response object's status tracking.
  // Actually, the simplest approach that works with defineApp's middleware
  // model: use a promise chain via the `cf` execution context's waitUntil
  // or simply rely on the fact that in dev mode, console.log is synchronous
  // enough. But we need the final status code.
  //
  // Better approach: use a Response wrapper. Since middleware runs before
  // route handlers, we can't know the final status yet. We'll use a
  // setTimeout(0) to defer logging, which runs after the current task.
  setTimeout(logRequest, 0);
};

export default defineApp([
  setCommonHeaders(),
  requestLogger,
  // GET /api/ping – returns {"pong":true} as JSON
  route("/api/ping", {
    get: () => {
      return Response.json({ pong: true }, { status: 200 });
    },
  }),
  render(Document, [route("/", Home)]),
]);

